+    #[test]
+    fn test_fsqlite_cache_pages_table_function_available_via_registry() {
+        let conn = Connection::open(":memory:").unwrap();
+        conn.execute("CREATE TABLE cache_probe (id INTEGER PRIMARY KEY, payload TEXT);")
+            .unwrap();
+        conn.execute("INSERT INTO cache_probe(id, payload) VALUES (1, 'alpha');")
+            .unwrap();
+        let _ = conn.query("SELECT payload FROM cache_probe;").unwrap();
+
+        let cx = Cx::new();
+        let mut txn = conn
+            .pager
+            .begin(&cx, fsqlite_pager::traits::TransactionMode::ReadOnly)
+            .unwrap();
+        let _ = txn.get_page(&cx, PageNumber::ONE).unwrap();
+        txn.rollback(&cx).unwrap();
+
+        let expected = conn.pager.cache_page_snapshots().unwrap();
+        assert!(
+            !expected.is_empty(),
+            "cache page diagnostics should expose at least one resident page"
+        );
+
+        let rows = conn
+            .query(
+                "SELECT pgno, version_txn_id, in_t1_or_t2, dirty, ref_count, access_count \
+                 FROM fsqlite_cache_pages() ORDER BY pgno;",
+            )
+            .unwrap();
+        assert_eq!(
+            rows.len(),
+            expected.len(),
+            "table-valued snapshot should report every resident page"
+        );
+
+        for (row, snapshot) in rows.iter().zip(expected.iter()) {
+            let expected_version = snapshot
+                .version_txn_id
+                .and_then(|value| i64::try_from(value).ok())
+                .map_or(SqliteValue::Null, SqliteValue::Integer);
+            let expected_queue = snapshot
+                .queue
+                .map(|queue| match queue.as_str() {
+                    "t1" | "t2" => SqliteValue::Text(queue.as_str().into()),
+                    _ => SqliteValue::Null,
+                })
+                .unwrap_or(SqliteValue::Null);
+            assert_eq!(
+                row_values(row),
+                vec![
+                    SqliteValue::Integer(i64::from(snapshot.page_no.get())),
+                    expected_version,
+                    expected_queue,
+                    SqliteValue::Integer(if snapshot.dirty { 1 } else { 0 }),
+                    SqliteValue::Integer(i64::from(snapshot.ref_count)),
+                    SqliteValue::Integer(i64::try_from(snapshot.access_count).unwrap_or(i64::MAX)),
+                ],
+            );
+        }
+    }
