+    #[test]
+    fn test_fsqlite_cache_pages_table_function_is_read_only_observer() {
+        let conn = Connection::open(":memory:").unwrap();
+        conn.query("PRAGMA fsqlite_cache_reset;").unwrap();
+
+        let cx = Cx::new();
+        let mut txn = conn
+            .pager
+            .begin(&cx, fsqlite_pager::traits::TransactionMode::ReadOnly)
+            .unwrap();
+        let _ = txn.get_page(&cx, PageNumber::ONE).unwrap();
+        txn.rollback(&cx).unwrap();
+
+        let before = conn.pager.cache_metrics_snapshot().unwrap();
+        let rows = conn
+            .query("SELECT pgno, access_count FROM fsqlite_cache_pages() ORDER BY pgno;")
+            .unwrap();
+        assert!(!rows.is_empty());
+        let after = conn.pager.cache_metrics_snapshot().unwrap();
+        assert_eq!(after, before, "cache observer must not perturb pager metrics");
+    }
